import subprocess

dwarf_file = "libcoreclr.dSYM/Contents/Resources/DWARF/libcoreclr"
offsets = [0x3e1700, 0x2615fc, 0x16c31c, 0x16c620, 0x18b678, 0x49cc]

for offset in offsets:
    result = subprocess.run(
        ["llvm-dwarfdump-18", "--lookup", hex(offset), "--name", dwarf_file],
        capture_output=True, text=True, timeout=30
    )
    # Get the function name from DW_AT_linkage_name or DW_AT_name in DW_TAG_subprogram
    in_subprogram = False
    func_name = None
    file_info = None
    for line in result.stdout.split('\n'):
        if 'DW_TAG_subprogram' in line:
            in_subprogram = True
        if in_subprogram and 'DW_AT_linkage_name' in line:
            func_name = line.split('"')[1] if '"' in line else line.split()[-1]
        if in_subprogram and 'DW_AT_name' in line and not func_name:
            func_name = line.split('"')[1] if '"' in line else line.split()[-1]
        if 'Line info:' in line:
            file_info = line.strip()

    # Use c++filt to demangle
    if func_name:
        demangled = subprocess.run(["c++filt", func_name], capture_output=True, text=True).stdout.strip()
    else:
        demangled = "?"

    print(f"0x{offset:06x}: {demangled}")
    if file_info:
        print(f"          {file_info}")
PYEOF

